import sys

class Solution:
    def longestStringChain(self, words: list[str]) -> int:
        dp = {}
        for word in sorted(words, key=len):
            dp[word] = 1
            for i in range(len(word)):
                prev_word = word[:i] + word[i+1:]
                if prev_word in dp:
                    dp[word] = max(dp[word], dp[prev_word] + 1)
        return max(dp.values())

